import pygame
import numpy as np
import math
import time

# Initialize pygame
pygame.init()

# Screen dimensions
WIDTH, HEIGHT = 1000, 700
screen = pygame.display.set_mode((WIDTH, HEIGHT))
pygame.display.set_caption("Interactive Sine Wave Visualization")

# Colors
BACKGROUND = (10, 10, 42)  # Deep navy blue
WAVE_COLOR = (0, 255, 255)  # Electric blue
PARTICLE_COLOR = (255, 215, 0)  # Gold
RIPPLE_COLOR = (0, 255, 255, 100)  # Cyan with transparency
CONTROL_PANEL_COLOR = (20, 10, 58, 200)  # Semi-transparent purple

# Font
font = pygame.font.SysFont(None, 36)


class SineWave:
    def __init__(self):
        self.amplitude = 100
        self.frequency = 0.02
        self.speed = 1
        self.phase = 0
        self.particles = []
        self.ripples = []
        self.wave_points = []
        self.reset_wave()

    def reset_wave(self):
        self.amplitude = 100
        self.frequency = 0.02
        self.speed = 1
        self.phase = 0
        self.particles = []
        self.ripples = []
        self.wave_points = []

    def update(self, mouse_y, mouse_x, mouse_pressed):
        # Update wave parameters based on mouse
        if mouse_pressed:
            self.amplitude = max(20, min(200, 200 - mouse_y))
            self.frequency = max(0.005, min(0.1, (mouse_x / WIDTH) * 0.1))

        # Update phase for animation
        self.phase += self.speed * 0.05

        # Generate wave points
        self.wave_points = []
        for x in range(0, WIDTH + 10, 10):
            y = HEIGHT // 2 + self.amplitude * math.sin((x * self.frequency) + self.phase)
            self.wave_points.append((x, y))

        # Add particles following the wave
        if len(self.particles) < 50:
            self.particles.append({
                'x': WIDTH,
                'y': HEIGHT // 2 + self.amplitude * math.sin(self.phase),
                'size': np.random.randint(2, 6),
                'speed': np.random.uniform(0.5, 2.0),
                'color': PARTICLE_COLOR
            })

        # Update particles
        for particle in self.particles[:]:
            particle['x'] -= particle['speed']
            particle['y'] = HEIGHT // 2 + self.amplitude * math.sin((particle['x'] * self.frequency) + self.phase)
            if particle['x'] < 0:
                self.particles.remove(particle)

        # Add ripple effect
        if mouse_pressed:
            self.ripples.append({
                'x': mouse_x,
                'y': mouse_y,
                'radius': 0,
                'max_radius': 100,
                'alpha': 255
            })

        # Update ripples
        for ripple in self.ripples[:]:
            ripple['radius'] += 3
            ripple['alpha'] -= 3
            if ripple['alpha'] <= 0:
                self.ripples.remove(ripple)

    def draw(self, surface):
        # Draw wave
        if len(self.wave_points) > 1:
            pygame.draw.lines(surface, WAVE_COLOR, False, self.wave_points, 3)

        # Draw particles
        for particle in self.particles:
            pygame.draw.circle(surface, particle['color'], (int(particle['x']), int(particle['y'])), particle['size'])

        # Draw ripples
        for ripple in self.ripples:
            alpha = max(0, min(255, ripple['alpha']))
            color = (0, 255, 255, alpha)
            pygame.draw.circle(surface, color, (int(ripple['x']), int(ripple['y'])), int(ripple['radius']), 2)


def main():
    clock = pygame.time.Clock()
    wave = SineWave()
    running = True

    # Audio setup
    sample_rate = 44100
    pygame.mixer.init(frequency=sample_rate, size=-16, channels=2, buffer=512)

    # Create audio tone
    def generate_tone(freq, duration):
        t = np.linspace(0, duration, int(sample_rate * duration), False)
        wave = np.sin(2 * np.pi * freq * t)
        wave = np.column_stack([wave, wave])  # Stereo
        wave = (wave * 32767).astype(np.int16)
        return wave

    # Play continuous tone
    base_freq = 261.63  # C4
    tone = generate_tone(base_freq, 1.0)
    sound = pygame.sndarray.make_sound(tone)
    sound.play(-1)  # Loop indefinitely

    print("Starting Interactive Sine Wave Visualization...")
    print("Controls:")
    print("- Drag vertically to change amplitude")
    print("- Click to change frequency")
    print("- Scroll to change speed")
    print("- Press 'R' to reset")
    print("- Press 'Q' to quit")

    while running:
        mouse_x, mouse_y = pygame.mouse.get_pos()
        mouse_pressed = pygame.mouse.get_pressed()[0]

        for event in pygame.event.get():
            if event.type == pygame.QUIT:
                running = False
            elif event.type == pygame.KEYDOWN:
                if event.key == pygame.K_r:
                    wave.reset_wave()
                elif event.key == pygame.K_q:
                    running = False
            elif event.type == pygame.MOUSEWHEEL:
                wave.speed = max(0.1, min(3.0, wave.speed + event.y * 0.1))

        # Update wave
        wave.update(mouse_y, mouse_x, mouse_pressed)

        # Draw everything
        screen.fill(BACKGROUND)

        # Draw gradient background
        for y in range(0, HEIGHT, 10):
            alpha = int(255 * (y / HEIGHT))
            pygame.draw.line(screen, (26, 10, 58, alpha), (0, y), (WIDTH, y))

        # Draw wave and effects
        wave.draw(screen)

        # Draw control panel
        pygame.draw.rect(screen, CONTROL_PANEL_COLOR, (0, HEIGHT - 60, WIDTH, 60))

        # Draw instructions
        text = font.render("Drag vertically to change amplitude | Click to change frequency | Scroll to change speed",
                           True, (255, 255, 255))
        screen.blit(text, (10, HEIGHT - 50))

        # Draw current parameters
        param_text = font.render(
            f"Amplitude: {int(wave.amplitude)} | Frequency: {wave.frequency:.3f} | Speed: {wave.speed:.2f}", True,
            (0, 255, 255))
        screen.blit(param_text, (10, HEIGHT - 25))

        pygame.display.flip()
        clock.tick(60)

    pygame.quit()
    print("Visualization ended.")


if __name__ == "__main__":
    main()